  const hwRoot = await initializeHardwareRoot();

  // 2. Regional bootstrap attestation
  const attestation = await performAttestation(hwRoot, regionalBootstrapService);

  // 3. CSR generation and submission
  const csr = await generateCSR({
    spiffeId: `spiffe://fleet.company.com/vehicles/${vehicleId}`,
    scope: 'vehicle-ota',
    ttl: 180
